example:
SELECT dept, AVG(salary) AS avg_salary
FROM Employee
GROUP BY dept;

SELECT s.name, c.course_name
FROM Students s
INNER JOIN Courses c ON s.course_id = c.id;

-- Correlated subquery
SELECT e.name FROM Employee e
WHERE e.salary > (SELECT AVG(salary) FROM Employee WHERE dept_id = e.dept_id);

SELECT name, salary,
  RANK() OVER (PARTITION BY dept_id ORDER BY salary DESC) AS dept_rank
FROM Employee;

SELECT DISTINCT salary
FROM Employee e1
WHERE (N-1) = (
  SELECT COUNT(DISTINCT salary) FROM Employee e2 WHERE e2.salary > e1.salary
);

WITH DeptAvg AS (
  SELECT dept_id, AVG(salary) AS avg_sal FROM Employee GROUP BY dept_id
)
SELECT e.name, d.avg_sal
FROM Employee e JOIN DeptAvg d ON e.dept_id = d.dept_id;

SELECT e1.name AS employee, e2.name AS manager
FROM Employee e1
JOIN Employee e2 ON e1.manager_id = e2.id;
